{
  "domain_analysis": {
    "business_context": "Parcel delivery logistics platform managing shipment lifecycle from creation through transit to delivery, with weight-based pricing tiers.",
    "bounded_context": "Shipment Management — covers shipment creation, state transitions, weight validation, and pricing classification.",
    "ubiquitous_language": [
      { "term": "Shipment", "definition": "A domain entity representing a parcel moving from a pickup address to a delivery address, with a defined weight and lifecycle state." },
      { "term": "Pickup Address", "definition": "The origin location where the parcel is collected from the sender." },
      { "term": "Delivery Address", "definition": "The destination location where the parcel is delivered to the recipient." },
      { "term": "Shipment State", "definition": "The lifecycle phase of a shipment. Valid states: Pending, In Transit, Delivered." },
      { "term": "Weight Bracket", "definition": "A classification tier derived from parcel weight that determines the pricing rate. Brackets: Standard (0–10 kg), Heavy (10–50 kg), Freight (>50 kg)." },
      { "term": "Standard", "definition": "Weight bracket for parcels weighing more than 0 kg up to and including 10 kg." },
      { "term": "Heavy", "definition": "Weight bracket for parcels weighing more than 10 kg up to and including 50 kg." },
      { "term": "Freight", "definition": "Weight bracket for parcels weighing more than 50 kg up to and including 1000 kg." }
    ]
  },

  "business_rules": [
    {
      "id": "BR-1",
      "rule": "A shipment requires both a pickup address and a delivery address at creation time.",
      "invariant": true,
      "invariant_justification": "A shipment without both endpoints is logically meaningless — it cannot be routed, priced, or dispatched. This is a data integrity constraint.",
      "testable_assertion": "Any attempt to create a shipment with a null or empty pickup address or delivery address must be rejected."
    },
    {
      "id": "BR-2",
      "rule": "Shipment state transitions are unidirectional: Pending → In Transit → Delivered. No backward transitions are permitted.",
      "invariant": true,
      "invariant_justification": "State regression (e.g., In Transit → Pending) would corrupt downstream processes such as tracking, billing, and SLA calculations. This is a state integrity constraint.",
      "testable_assertion": "Attempting to transition a shipment from In Transit to Pending, or from Delivered to any other state, must be rejected."
    },
    {
      "id": "BR-3",
      "rule": "Delivered is a terminal state. No further state changes are allowed on a delivered shipment.",
      "invariant": true,
      "invariant_justification": "Delivery triggers settlement, proof-of-delivery records, and customer notifications. Reopening a delivered shipment would corrupt financial and audit records.",
      "testable_assertion": "Any state change attempted on a shipment with state Delivered must be rejected."
    },
    {
      "id": "BR-4",
      "rule": "Shipment weight must be strictly greater than 0 kg and must not exceed 1000 kg.",
      "invariant": true,
      "invariant_justification": "Zero or negative weight is physically impossible for a real parcel. The 1000 kg upper bound is a physical/operational constraint of the delivery network (vehicle capacity, handling equipment). Violating either corrupts pricing and logistics planning.",
      "testable_assertion": "Creating or updating a shipment with weight <= 0 or weight > 1000 must be rejected."
    },
    {
      "id": "BR-5",
      "rule": "Weight bracket classification: Standard = weight in (0, 10], Heavy = weight in (10, 50], Freight = weight in (50, 1000].",
      "invariant": false,
      "invariant_justification": "Bracket thresholds are a business pricing policy. A VP could adjust the boundaries (e.g., raise Standard to 15 kg) without corrupting system integrity.",
      "testable_assertion": "A shipment with weight 10 kg is classified as Standard; 10.01 kg as Heavy; 50 kg as Heavy; 50.01 kg as Freight."
    },
    {
      "id": "BR-6",
      "rule": "A newly created shipment must begin in Pending state.",
      "invariant": true,
      "invariant_justification": "Creating a shipment directly in In Transit or Delivered would bypass pickup scheduling, validation, and label generation. This is a lifecycle integrity constraint.",
      "testable_assertion": "Upon successful creation, a shipment's state must be Pending."
    }
  ],

  "acceptance_criteria": [
    {
      "id": "AC-1",
      "given": "A valid pickup address, delivery address, and weight of 5 kg",
      "when": "A shipment is created",
      "then": "The shipment is persisted in Pending state with weight bracket Standard"
    },
    {
      "id": "AC-2",
      "given": "A shipment creation request missing the pickup address",
      "when": "The system attempts to create the shipment",
      "then": "The creation is rejected with a validation error indicating pickup address is required"
    },
    {
      "id": "AC-3",
      "given": "A shipment creation request missing the delivery address",
      "when": "The system attempts to create the shipment",
      "then": "The creation is rejected with a validation error indicating delivery address is required"
    },
    {
      "id": "AC-4",
      "given": "A shipment in Pending state",
      "when": "The shipment is transitioned to In Transit",
      "then": "The state updates to In Transit successfully"
    },
    {
      "id": "AC-5",
      "given": "A shipment in In Transit state",
      "when": "The shipment is transitioned to Delivered",
      "then": "The state updates to Delivered successfully and becomes final"
    },
    {
      "id": "AC-6",
      "given": "A shipment in In Transit state",
      "when": "An attempt is made to transition it back to Pending",
      "then": "The transition is rejected and the shipment remains In Transit"
    },
    {
      "id": "AC-7",
      "given": "A shipment in Delivered state",
      "when": "Any state change is attempted (to Pending or In Transit)",
      "then": "The transition is rejected and the shipment remains Delivered"
    },
    {
      "id": "AC-8",
      "given": "A shipment creation request with weight 0 kg",
      "when": "The system attempts to create the shipment",
      "then": "The creation is rejected with a validation error indicating weight must be positive"
    },
    {
      "id": "AC-9",
      "given": "A shipment creation request with weight 1001 kg",
      "when": "The system attempts to create the shipment",
      "then": "The creation is rejected with a validation error indicating weight cannot exceed 1000 kg"
    },
    {
      "id": "AC-10",
      "given": "A shipment creation request with weight 10 kg",
      "when": "The shipment is created",
      "then": "The weight bracket is classified as Standard"
    },
    {
      "id": "AC-11",
      "given": "A shipment creation request with weight 25 kg",
      "when": "The shipment is created",
      "then": "The weight bracket is classified as Heavy"
    },
    {
      "id": "AC-12",
      "given": "A shipment creation request with weight 75 kg",
      "when": "The shipment is created",
      "then": "The weight bracket is classified as Freight"
    },
    {
      "id": "AC-13",
      "given": "A shipment in Pending state",
      "when": "An attempt is made to transition it directly to Delivered (skipping In Transit)",
      "then": "The transition is rejected — shipments must pass through In Transit before Delivered"
    }
  ],

  "edge_cases": [
    { "scenario": "Weight is exactly 10 kg (Standard/Heavy boundary)", "expected_behavior": "Classified as Standard per the bracket definition (0, 10]." },
    { "scenario": "Weight is exactly 50 kg (Heavy/Freight boundary)", "expected_behavior": "Classified as Heavy per the bracket definition (10, 50]." },
    { "scenario": "Weight is exactly 1000 kg (upper limit)", "expected_behavior": "Accepted and classified as Freight. This is the maximum allowed weight." },
    { "scenario": "Weight is a very small positive number (e.g., 0.001 kg)", "expected_behavior": "Accepted and classified as Standard. The spec says positive, not a minimum practical weight." },
    { "scenario": "Weight is negative (e.g., -5 kg)", "expected_behavior": "Rejected — weight must be strictly positive." },
    { "scenario": "Pending shipment attempts direct transition to Delivered", "expected_behavior": "Rejected. The spec implies a linear lifecycle: Pending → In Transit → Delivered. Skipping In Transit is not permitted." },
    { "scenario": "Pickup address and delivery address are identical", "expected_behavior": "Spec does not prohibit this. Flag for product clarification — it may indicate a data entry error but is not explicitly invalid." },
    { "scenario": "Weight is provided with extreme decimal precision (e.g., 10.0000001 kg)", "expected_behavior": "Classified as Heavy — it exceeds the 10 kg Standard boundary. Precision handling should be defined by implementation." }
  ],

  "business_impact": {
    "financial": "Weight bracket classification directly drives revenue. Misclassification (e.g., Freight parcel charged as Standard) causes revenue leakage. Correct enforcement of brackets protects margin integrity.",
    "operational": "State machine enforcement prevents operational chaos — dispatchers and drivers rely on accurate shipment states. Allowing backward transitions would break route planning, warehouse operations, and delivery scheduling.",
    "user": "Customers expect shipment tracking to reflect reality. A delivered parcel reverting to In Transit would erode trust. Clear validation errors at creation time prevent frustration from failed shipments downstream.",
    "risk": "Primary risk is revenue leakage from weight bracket miscalculation. Secondary risk is operational integrity failure if state machine invariants are violated. Low compliance risk given the spec does not reference regulated goods.",
    "stakeholders_affected": [
      { "group": "Shippers (Customers)", "impact": "Depend on clear validation at creation time and accurate tracking through the shipment lifecycle." },
      { "group": "Operations / Dispatch", "impact": "Rely on state machine correctness to schedule pickups, route drivers, and manage warehouse handoffs." },
      { "group": "Finance / Billing", "impact": "Revenue depends on correct weight bracket classification. Terminal Delivered state triggers invoicing." },
      { "group": "Drivers / Couriers", "impact": "Depend on accurate state to know which shipments to pick up and deliver. Backward transitions would create confusion." },
      { "group": "Recipients", "impact": "Expect reliable delivery status. Terminal Delivered state must reflect physical reality." }
    ]
  },

  "confidence": {
    "level": 72,
    "reasoning": "The spec is clear on core lifecycle rules, weight constraints, and bracket definitions. However, several domain details are unspecified: whether Pending→Delivered skip is allowed, boundary inclusivity for weight brackets (I assumed upper-inclusive based on common logistics convention), address validation depth, and whether weight can change after creation. These gaps reduce confidence from high to moderate.",
    "high_confidence_areas": [
      "State machine: Pending → In Transit → Delivered with no backward transitions",
      "Delivered is terminal and immutable",
      "Weight must be positive and <= 1000 kg",
      "Three weight brackets exist: Standard, Heavy, Freight",
      "Shipment requires both pickup and delivery address"
    ],
    "low_confidence_areas": [
      "Bracket boundary inclusivity — spec says '0-10', '10-50', 'over 50' but does not clarify whether 10 kg is Standard or Heavy",
      "Whether Pending → Delivered (skipping In Transit) is allowed or blocked",
      "Whether weight or addresses can be modified after shipment creation",
      "Address validation requirements beyond 'exists'",
      "Whether additional states (e.g., Cancelled, Failed Delivery, Returned) exist in the full lifecycle"
    ],
    "assumptions": [
      "Bracket boundaries are upper-inclusive: Standard = (0, 10], Heavy = (10, 50], Freight = (50, 1000]",
      "Pending → Delivered directly is not allowed — the linear lifecycle must be followed",
      "Shipments are created in Pending state by default",
      "Weight is immutable after shipment creation (spec does not mention modification)",
      "No Cancelled or Return states exist — spec describes only three states"
    ]
  },

  "escalations": [
    {
      "type": "ambiguity",
      "description": "Weight bracket boundary: the spec says '0-10 kg is standard, 10-50 kg is heavy'. It is ambiguous whether a parcel weighing exactly 10 kg falls into Standard or Heavy. Same issue at the 50 kg boundary.",
      "affected_stakeholders": ["Finance / Billing", "Shippers (Customers)"],
      "options": ["A: Upper-inclusive (10 kg = Standard, 50 kg = Heavy)", "B: Lower-inclusive (10 kg = Heavy, 50 kg = Freight)"],
      "recommendation": "Option A — standard logistics convention is to include the boundary in the lower bracket, keeping the cheaper classification. Confirm with product."
    },
    {
      "type": "ambiguity",
      "description": "Can a shipment skip In Transit and go directly from Pending to Delivered? The spec says 'once in transit, it cannot be sent back to pending' but does not explicitly define all valid transitions.",
      "affected_stakeholders": ["Operations / Dispatch", "Drivers / Couriers"],
      "options": ["A: Strictly linear — only Pending→InTransit and InTransit→Delivered are valid", "B: Allow Pending→Delivered for edge cases like in-store pickup"],
      "recommendation": "Option A — strict linear flow. If shortcuts are needed, they should be explicitly modeled as separate flows."
    },
    {
      "type": "missing_context",
      "description": "No mention of shipment cancellation, failed delivery attempts, or return-to-sender flows. Real logistics always has these. Are they out of scope for this iteration, or an oversight?",
      "affected_stakeholders": ["Shippers (Customers)", "Operations / Dispatch", "Recipients"],
      "options": ["A: Out of scope for MVP — model only the three stated states", "B: Add Cancelled and Failed states now to avoid costly migration later"],
      "recommendation": "Option A for immediate implementation, but flag in the domain model that the state machine will need extension. Design the state transition logic to be open for extension."
    }
  ],

  "rejection_reasons": []
}

